-- Stored procedure: a multi-step workflow, invoked with CALL, no return value
CREATE PROCEDURE transfer_funds(IN from_id INT, IN to_id INT, IN amount DECIMAL(12,2))
BEGIN
    UPDATE accounts SET balance = balance - amount WHERE id = from_id;
    UPDATE accounts SET balance = balance + amount WHERE id = to_id;
    INSERT INTO transaction_log (from_id, to_id, amount) VALUES (from_id, to_id, amount);
END;

CALL transfer_funds(501, 502, 200.00);

-- Function: must return a value, usable directly inside a SELECT
CREATE FUNCTION calculate_tax(amount DECIMAL(12,2))
RETURNS DECIMAL(12,2)
BEGIN
    RETURN amount * 0.18;
END;

SELECT id, amount, calculate_tax(amount) AS tax
FROM invoices;

-- Audit table to record every balance change
CREATE TABLE account_audit (
    audit_id INT AUTO_INCREMENT PRIMARY KEY,
    account_id INT,
    old_balance DECIMAL(12,2),
    new_balance DECIMAL(12,2),
    changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Trigger fires automatically after any UPDATE to accounts.balance
CREATE TRIGGER trg_log_balance_change
AFTER UPDATE ON accounts
FOR EACH ROW
BEGIN
    IF OLD.balance <> NEW.balance THEN
        INSERT INTO account_audit (account_id, old_balance, new_balance)
        VALUES (OLD.id, OLD.balance, NEW.balance);
    END IF;
END;

-- Any application simply does a normal UPDATE — no explicit logging call needed:
UPDATE accounts SET balance = balance - 200.00 WHERE id = 501;
